-- =============================================================================
-- LANDING TABLE: L_HCM_SALARY_BC
-- =============================================================================
-- Source: HcmTopModelAnalyticsGlobalAM.HCMExtractAM.HcmCompBiccExtractAM.SalaryExtractPVO
--
-- COPY_DATA loads the raw CSV into this table.
-- The load procedure then cherry-picks columns into stg_fbx_hcm_salary.
--
-- SETUP (two steps):
--   1. Create the external table (defines the CSV structure)
--   2. Create the landing table as a copy of the external table structure
--
-- IF BICC SCHEMA CHANGES:
--   DROP TABLE L_HCM_SALARY_BC;
--   DROP TABLE EXT_HCM_SALARY_BC;
--   Re-run Step 1 with updated column_list, then re-run Step 2.
-- =============================================================================


-- Step 1: Create external table (one-time, defines CSV structure)
-- Column order MUST match BICC CSV header (alphabetical).
BEGIN
  DBMS_CLOUD.CREATE_EXTERNAL_TABLE(
    table_name      => 'EXT_HCM_SALARY_BC',
    credential_name => '<OCI_CREDENTIAL_NAME>',
    file_uri_list   => 'https://objectstorage.us-ashburn-1.oraclecloud.com/n/<OCI_NAMESPACE>/b/<OCI_BUCKET_NAME>/o/hcm_salary_unzipped.csv',
    format          => json_object(
                         'type' value 'csv',
                         'skipheaders' value '1'
                       ),
    column_list     => 'ACTIONID VARCHAR2(4000),ACTIONOCCURRENCEID VARCHAR2(4000),ACTIONREASONID VARCHAR2(4000),ADJUSTMENTAMOUNT VARCHAR2(4000),ADJUSTMENTAMOUNTSCALE VARCHAR2(4000),ADJUSTMENTPERCENT VARCHAR2(4000),ADJUSTMENTPERCENTSCALE VARCHAR2(4000),AMOUNTROUNDINGCODE VARCHAR2(4000),ANNUALFTSALARY VARCHAR2(4000),ANNUALROUNDINGCODE VARCHAR2(4000),ANNUALSALARY VARCHAR2(4000),ASSIGGRADELADDERID VARCHAR2(4000),ASSIGGRADESTEPID VARCHAR2(4000),ASSIGLOCATIONID VARCHAR2(4000),ASSIGNMENTID VARCHAR2(4000),ASSIGNMENTTYPE VARCHAR2(4000),BUSINESSGROUPID VARCHAR2(4000),BUSINESSUNITID VARCHAR2(4000),COMPARATIO VARCHAR2(4000),COMPARATIOSCALE VARCHAR2(4000),COMPONENTUSAGE VARCHAR2(4000),CREATEDBY VARCHAR2(4000),CREATIONDATE VARCHAR2(4000),CURRENCYCODE VARCHAR2(4000),DATEFROM VARCHAR2(4000),DATETO VARCHAR2(4000),DISABLECOMPARATIO VARCHAR2(4000),DISABLEQUARTILE VARCHAR2(4000),DISABLEQUINTILE VARCHAR2(4000),DISABLERANGEPOSITION VARCHAR2(4000),ELEMENTENTRYID VARCHAR2(4000),ELEMENTTYPEID VARCHAR2(4000),ELEMENTUSAGELEVEL VARCHAR2(4000),FORCEDRANKING VARCHAR2(4000),FTEIMPACT VARCHAR2(4000),FTEVALUE VARCHAR2(4000),GEOGRAPHYID VARCHAR2(4000),GEOGRAPHYTYPEID VARCHAR2(4000),GRADEID VARCHAR2(4000),GRADERATEMINIMUMLIMIT VARCHAR2(4000),INPUTVALUEID VARCHAR2(4000),JOBID VARCHAR2(4000),LASTUPDATEDATE VARCHAR2(4000),LASTUPDATELOGIN VARCHAR2(4000),LASTUPDATEDBY VARCHAR2(4000),LEGALENTITYID VARCHAR2(4000),LEGISLATIVEDATAGROUPID VARCHAR2(4000),MULTIPLECOMPONENTS VARCHAR2(4000),NEXTPERFREVIEWDATE VARCHAR2(4000),NEXTSALREVIEWDATE VARCHAR2(4000),OBJECTVERSIONNUMBER VARCHAR2(4000),PAYROLLFACTOR VARCHAR2(4000),PAYROLLFREQUENCYCODE VARCHAR2(4000),PERFORMANCERATING VARCHAR2(4000),PERFORMANCEREVIEWID VARCHAR2(4000),PERSONID VARCHAR2(4000),QUARTILE VARCHAR2(4000),QUINTILE VARCHAR2(4000),RANGEANALYTICSFOREMP VARCHAR2(4000),RANGEANALYTICSFORMGR VARCHAR2(4000),RANGEERRORWARNING VARCHAR2(4000),RANGEPOSITION VARCHAR2(4000),RANGEPOSITIONSCALE VARCHAR2(4000),RANGEROUNDINGCODE VARCHAR2(4000),RATEDEFAULTAMOUNT VARCHAR2(4000),RATEFACTOR VARCHAR2(4000),RATEID VARCHAR2(4000),RATEMAXAMOUNT VARCHAR2(4000),RATEMIDAMOUNT VARCHAR2(4000),RATEMINAMOUNT VARCHAR2(4000),REVIEWDATE VARCHAR2(4000),SALARYAMOUNT VARCHAR2(4000),SALARYAMOUNTSCALE VARCHAR2(4000),SALARYAPPROVED VARCHAR2(4000),SALARYBASISCODE VARCHAR2(4000),SALARYBASISID VARCHAR2(4000),SALARYBASISTYPE VARCHAR2(4000),SALARYEFFECTIVEENDDATE VARCHAR2(4000),SALARYEFFECTIVESTARTDATE VARCHAR2(4000),SALARYFACTOR VARCHAR2(4000),SALARYID VARCHAR2(4000),SALARYJUSTIFICATION VARCHAR2(4000),SALARYRANGESCALE VARCHAR2(4000),SALARYREASONCODE VARCHAR2(4000),SALARYTRANSACTIONSTATUS VARCHAR2(4000),TOTALBASEPAY VARCHAR2(4000),TOTALCOMPONENTADJAMT VARCHAR2(4000),TOTALCOMPONENTADJPERCENT VARCHAR2(4000),WORKATHOME VARCHAR2(4000),ZONEGRADERATEID VARCHAR2(4000)'
  );
END;
/

-- Step 2: Create landing table from the external table structure
CREATE TABLE L_HCM_SALARY_BC AS SELECT * FROM EXT_HCM_SALARY_BC WHERE 1=0;
